(()=>{'use strict';
const $=s=>document.querySelector(s),T=v=>String(v??'').trim(),N=v=>Number(String(v??'').replace(/,/g,''))||0,F=n=>N(n).toLocaleString('th-TH');
let current=null;
function set(p,msg,step){$('#bar').style.width=Math.max(0,Math.min(100,p))+'%';$('#pct').textContent=Math.round(p)+'%';$('#status').textContent=msg;document.querySelectorAll('.step').forEach(x=>x.classList.toggle('on',x.dataset.s===step))}
function norm(s){return T(s).toLowerCase().replace(/[\s_\-./()[\]:]+/g,'')}
function col(o,names){const ks=Object.keys(o),m=new Map(ks.map(k=>[norm(k),k]));for(const n of names){const k=m.get(norm(n));if(k)return k}for(const k of ks)for(const n of names)if(norm(k).includes(norm(n))||norm(n).includes(norm(k)))return k;}
function val(o,names,d=''){const k=col(o,names);return k?T(o[k])||d:d}
function num(o,names){const k=col(o,names);return k?N(o[k]):0}
function iso(v){if(v==null||v==='')return'';if(v instanceof Date&&!isNaN(v))return v.toISOString().slice(0,10);if(typeof v==='number'&&v>30000&&window.XLSX){const d=XLSX.SSF.parse_date_code(v);if(d)return `${d.y}-${String(d.m).padStart(2,'0')}-${String(d.d).padStart(2,'0')}`}const s=T(v);const d=new Date(s);return isNaN(d)?s.slice(0,10):d.toISOString().slice(0,10)}
function row(o,i){const tid=val(o,['TelesaleId','TelesalesID','TeleSaleID','TeleSale Id','TeleSaleCode','Telesale Code']);const tn=val(o,['TelesaleName','TelesalesName','TeleSaleName','TeleSale Name']);const sid=val(o,['SO_SalespersonID','SalespersonID','PS','PS Code']);const sn=val(o,['Salesperson_Name','Salesperson Name','SalesName','PSName']);const qty=num(o,['ShipQtyPCS','ShipQtyPC','QtyShipPCS','Qty PCS','Qty','Quantity','PCS']);const unit=num(o,['SO_UnitPrice','UnitPrice','Unit Price','Price']);const line=num(o,['LineAmtBeforeDisc','Line Amount Before Disc','DetailAmt','LineAmt','Line Amount','Correct Amount','NetAmt']);const code=val(o,['SKU_Code','SKUCode','SKU Code','ItemCode','ProductCode','Product Code']);return{date:iso(val(o,['InvcDate','Invoice_Date','InvoiceDate','ShipDateAct','ShipDate','SO_Date','OrdDate','OrderDate','Date'])),inv:val(o,['InvcNbr','InvoiceNo','Invoice No','Invoice_No','BillNo','DocNo','OrderNo','SO No','SONo'])||('NO-BILL-'+(i+1)),store:val(o,['Customer Name','CustomerName','ShipName','Ship To Name','c_Name','Store','BranchName'])||'ไม่ระบุร้าน',ps:[sid,sn].filter(Boolean).join(' ')||'ไม่ระบุ PS',tele:[tid,tn].filter(Boolean).join(' '),isTele:!!(tid||tn),sku:code||val(o,['SKU_Desc','ProductName','Product','ItemName','Description'])||'ไม่ระบุสินค้า',qty,amt:line||(unit*qty)}}
function readSheets(wb){let out=[];for(const name of wb.SheetNames){const ws=wb.Sheets[name],aoa=XLSX.utils.sheet_to_json(ws,{header:1,defval:'',raw:false});for(let i=0;i<Math.min(100,aoa.length);i++){const h=(aoa[i]||[]).map(T),score=h.filter(x=>/sku|qty|pcs|ship|customer|sales|tele|invc|invoice|brand|สินค้า|ร้าน/i.test(x)).length;if(score>=3){out=aoa.slice(i+1).map(r=>Object.fromEntries(h.map((k,j)=>[k||('c'+j),r[j]]))).map(row).filter(r=>r.qty||r.amt||r.sku);if(out.length)return out}}}return out}
async function readPivot(buf){if(!window.JSZip)return[];const zip=await JSZip.loadAsync(buf),defs=Object.keys(zip.files).filter(k=>/^xl\/pivotCache\/pivotCacheDefinition\d+\.xml$/.test(k)).sort(),recs=Object.keys(zip.files).filter(k=>/^xl\/pivotCache\/pivotCacheRecords\d+\.xml$/.test(k)).sort();for(let z=0;z<Math.min(defs.length,recs.length);z++){const df=zip.file(defs[z]),rf=zip.file(recs[z]);if(!df||!rf)continue;const doc=new DOMParser().parseFromString(await df.async('string'),'text/xml'),fields=[...doc.getElementsByTagName('cacheField')].map(cf=>{let shared=[];const si=[...cf.childNodes].find(n=>n.nodeType===1&&n.localName==='sharedItems');if(si)[...si.childNodes].forEach(ch=>{if(ch.nodeType!==1)return;let v=ch.getAttribute('v')??'';if(ch.localName==='n')v=N(v);if(ch.localName==='d')v=T(v).slice(0,10);if(ch.localName==='m')v='';shared.push(v)});return{name:cf.getAttribute('name')||'',shared}});const rtx=await rf.async('string'),out=[];let rr=/<r>([\s\S]*?)<\/r>/g,er=/<(x|n|s|d|b|m)(?:\s+[^>]*?v="([^"]*)")?[^>]*\/>/g,m,rec=0;while((m=rr.exec(rtx))){let body=m[1],em,i=0,o={};er.lastIndex=0;while((em=er.exec(body))){const k=fields[i]?.name;if(k){const tag=em[1],v=em[2];o[k]=tag==='x'?(fields[i]?.shared[N(v)]??''):(tag==='n'?N(v):(tag==='m'?'':T(v)))}i++}const r=row(o,rec++);if(r.qty||r.amt||r.sku)out.push(r);if(rec%5000===0)set(55+Math.min(30,rec/2500),'กำลังแยกข้อมูล '+F(rec)+' แถว','parse')}if(out.length)return out}return[]}
function summary(rows,f){const stores=new Set(rows.map(r=>r.store)),ps=new Set(rows.map(r=>r.ps)),teleBills=new Set(rows.filter(r=>r.isTele).map(r=>[r.inv,r.store,r.tele].join('|')));return{fileName:f.name,fileSize:f.size,checkedAt:new Date().toISOString(),rows:rows.length,stores:stores.size,ps:ps.size,teleBills:teleBills.size,qty:rows.reduce((s,r)=>s+N(r.qty),0),amount:rows.reduce((s,r)=>s+N(r.amt),0),status:'local-ready'}}
async function handleFile(f){current=null;$('#fileName').textContent=f.name+' · '+(f.size/1024/1024).toFixed(2)+' MB';set(5,'เลือกไฟล์แล้ว','pick');const buf=await new Promise((resolve,reject)=>{const r=new FileReader();r.onprogress=e=>{if(e.lengthComputable)set(5+(e.loaded/e.total)*35,'กำลังอ่านไฟล์ '+F(Math.round(e.loaded/1024))+' / '+F(Math.round(e.total/1024))+' KB','read')};r.onload=()=>resolve(r.result);r.onerror=reject;r.readAsArrayBuffer(f)});set(45,'อ่านไฟล์เสร็จ กำลังแปลงข้อมูล','parse');let rows=await readPivot(buf);if(!rows.length){set(70,'ไม่พบ pivot cache กำลังอ่าน worksheet','parse');rows=readSheets(XLSX.read(buf,{type:'array',cellDates:true,raw:false}))}set(88,'กำลังสร้าง index สรุป','index');current=summary(rows,f);set(100,'พร้อมใช้งานในโหมดทดสอบ','ready');show(current)}
function show(s){$('#rows').textContent=F(s.rows);$('#stores').textContent=F(s.stores);$('#ps').textContent=F(s.ps);$('#tele').textContent=F(s.teleBills);$('#result').innerHTML=`ไฟล์: <b>${s.fileName}</b><br>แถว: ${F(s.rows)} · ร้าน: ${F(s.stores)} · PS: ${F(s.ps)} · Telesale bills: ${F(s.teleBills)}<br>จำนวนรวม: ${F(s.qty)} ชิ้น · ยอดรวม: ${s.amount.toLocaleString('th-TH',{minimumFractionDigits:2,maximumFractionDigits:2})} บาท<br><span class="pill local">โหมดทดสอบในเครื่อง ยังไม่ได้อัปโหลดขึ้นระบบกลาง</span>`}
function hist(){let a=[];try{a=JSON.parse(localStorage.getItem('doit-admin-history')||'[]')}catch{}const h=$('#hist');h.innerHTML=a.length?a.map(x=>`<tr><td>${new Date(x.checkedAt).toLocaleString('th-TH')}</td><td>${x.fileName}</td><td>${F(x.rows)}</td><td>${F(x.stores)}</td><td>${F(x.ps)}</td><td>${F(x.teleBills)}</td><td><span class="pill local">local</span></td></tr>`).join(''):'<tr><td colspan="7" class="muted">ยังไม่มีประวัติ</td></tr>'}
function save(){if(!current){alert('ยังไม่มีไฟล์ที่ตรวจสำเร็จ');return}let a=[];try{a=JSON.parse(localStorage.getItem('doit-admin-history')||'[]')}catch{}a.unshift(current);localStorage.setItem('doit-admin-history',JSON.stringify(a.slice(0,20)));hist();alert('บันทึกเวอร์ชันทดสอบแล้ว')}
function bind(){$('#choose').onclick=()=>$('#file').click();$('#file').onchange=e=>{const f=e.target.files&&e.target.files[0];if(f)handleFile(f).catch(err=>{console.error(err);set(100,'ตรวจไฟล์ไม่สำเร็จ: '+(err.message||err),'ready')})};$('#clear').onclick=()=>location.reload();$('#saveVersion').onclick=save;$('#clearHistory').onclick=()=>{localStorage.removeItem('doit-admin-history');hist()};hist()}
document.addEventListener('DOMContentLoaded',bind);
})();